DarkRPUI=DarkRPUI or {}; DarkRPUI.F4=DarkRPUI.F4 or {}
function DarkRPUI.F4.Open() if IsValid(DarkRPUI.F4.Frame) then DarkRPUI.F4.Frame:Remove() end local f=DarkRPUI.UI.CreateFrame("CITY COMMAND CENTER",1120,760); DarkRPUI.F4.Frame=f; local body=vgui.Create("DPanel",f); body:Dock(FILL); body:DockMargin(0,72,18,18); body.Paint=nil; local active="dashboard"; local builders={dashboard=DarkRPUI.F4.BuildDashboard,jobs=DarkRPUI.F4.BuildJobs,shop=DarkRPUI.F4.BuildShop,admin=DarkRPUI.F4.BuildAdminStats,upgrades=DarkRPUI.F4.BuildPlayerUpgrades}; DarkRPUI.F4.BuildSidebar(f,body,function(tab) active=tab; builders[tab](body) end,function() return active end); builders[active](body); DarkRPUI.UI.CloseButton(f):SetPos(f:GetWide()-58,14); f:MakePopup() end
hook.Add("ShowSpare2","DarkRPUI.F4.Show",function() if DarkRPUI.Config.EnableF4 then DarkRPUI.F4.Open(); return false end end)
